import{_ as h}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as r,c as b,f as s,q as p,D as n,O as t,j as d,g as e,k as l,X as o}from"./chunks/runtime-core.esm-bundler.DoiTk7Jm.js";const f=JSON.parse('{"title":"Agent Skills","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/工具提效/Agent Skills.md","filePath":"column/AIFuture/工具提效/Agent Skills.md","lastUpdated":1779160644000}'),u={name:"column/AIFuture/工具提效/Agent Skills.md"};function k(A,a,m,E,S,_){const c=r("ArticleMetadata"),i=r("Mermaid");return s(),b("div",null,[a[2]||(a[2]=p("h1",{id:"agent-skills",tabindex:"-1"},[e("Agent Skills "),p("a",{class:"header-anchor",href:"#agent-skills","aria-label":'Permalink to "Agent Skills"'},"​")],-1)),n(c),a[3]||(a[3]=t('<p>Agent Skills 可以理解为给 AI Agent 准备的“可复用能力包”。它把某类任务需要的说明、流程、脚本、模板、示例文件放在一起，让 Agent 遇到对应任务时按固定方法执行。</p><p>简单说：</p><blockquote><p>Prompt 是一次性说明，Skill 是可复用的工作方法。</p></blockquote><h2 id="一、为什么需要-skills" tabindex="-1">一、为什么需要 Skills <a class="header-anchor" href="#一、为什么需要-skills" aria-label="Permalink to &quot;一、为什么需要 Skills&quot;">​</a></h2><p>只靠一次性提示词，很难保证每次执行都稳定。</p><p>比如你经常让 AI 做这些事：</p><ul><li>按固定格式整理会议纪要</li><li>按团队规范生成代码评审意见</li><li>把 Excel 数据转换成图表和结论</li><li>把产品需求拆成任务清单</li><li>按公司模板生成周报</li><li>根据项目规范改代码、跑测试、写说明</li></ul><p>如果每次都重新解释一遍，成本很高，也容易漏信息。Skill 的价值就是把这些流程固化下来。</p>',8)),(s(),d(o,null,{default:l(()=>[n(i,{id:"mermaid-58",class:"mermaid",graph:"flowchart%20TD%0A%20%20A%5B%22%E9%AB%98%E9%A2%91%E4%BB%BB%E5%8A%A1%22%5D%20--%3E%20B%5B%22%E6%B2%89%E6%B7%80%E6%B5%81%E7%A8%8B%22%5D%0A%20%20B%20--%3E%20C%5B%22%E6%95%B4%E7%90%86%E6%A8%A1%E6%9D%BF%E5%92%8C%E8%84%9A%E6%9C%AC%22%5D%0A%20%20C%20--%3E%20D%5B%22%E5%BD%A2%E6%88%90%20Skill%22%5D%0A%20%20D%20--%3E%20E%5B%22Agent%20%E6%8C%89%20Skill%20%E6%89%A7%E8%A1%8C%22%5D%0A%20%20E%20--%3E%20F%5B%22%E7%A8%B3%E5%AE%9A%E5%A4%8D%E7%94%A8%22%5D%0A"})]),fallback:l(()=>[...a[0]||(a[0]=[e(" Loading... ",-1)])]),_:1})),a[4]||(a[4]=t('<h2 id="二、skill-里通常有什么" tabindex="-1">二、Skill 里通常有什么 <a class="header-anchor" href="#二、skill-里通常有什么" aria-label="Permalink to &quot;二、Skill 里通常有什么&quot;">​</a></h2><p>一个实用 Skill 通常包含这些内容：</p><table tabindex="0"><thead><tr><th>内容</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td>触发条件</td><td>说明什么时候使用</td><td>“用户要求生成周报时使用”</td></tr><tr><td>工作流程</td><td>固定执行步骤</td><td>“先读取数据，再聚合，再输出表格”</td></tr><tr><td>输入要求</td><td>用户需要提供什么</td><td>日期范围、数据文件、目标格式</td></tr><tr><td>输出格式</td><td>最终结果长什么样</td><td>Markdown、JSON、表格</td></tr><tr><td>约束规则</td><td>哪些事不能做</td><td>不编造数据、不发送外部消息</td></tr><tr><td>脚本工具</td><td>复用自动化能力</td><td>表格解析脚本、图片处理脚本</td></tr><tr><td>示例文件</td><td>让 Agent 模仿</td><td>模板、样例、参考输出</td></tr></tbody></table><h2 id="三、skill-和-agents-md-的区别" tabindex="-1">三、Skill 和 AGENTS.md 的区别 <a class="header-anchor" href="#三、skill-和-agents-md-的区别" aria-label="Permalink to &quot;三、Skill 和 AGENTS.md 的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>AGENTS.md</th><th>Skill</th></tr></thead><tbody><tr><td>作用范围</td><td>项目或仓库级规则</td><td>某类任务的能力模块</td></tr><tr><td>关注点</td><td>约束 Agent 行为</td><td>指导 Agent 完成任务</td></tr><tr><td>生命周期</td><td>长期生效</td><td>需要时触发</td></tr><tr><td>内容形式</td><td>规则、规范、流程</td><td>说明、脚本、模板、资产</td></tr></tbody></table><p>可以这样理解：</p>',6)),(s(),d(o,null,{default:l(()=>[n(i,{id:"mermaid-226",class:"mermaid",graph:"flowchart%20LR%0A%20%20A%5B%22AGENTS.md%22%5D%20--%3E%20B%5B%22%E5%91%8A%E8%AF%89%20Agent%20%E6%80%8E%E4%B9%88%E5%9C%A8%E8%BF%99%E4%B8%AA%E9%A1%B9%E7%9B%AE%E9%87%8C%E5%81%9A%E4%BA%8B%22%5D%0A%20%20C%5B%22Skill%22%5D%20--%3E%20D%5B%22%E5%91%8A%E8%AF%89%20Agent%20%E6%9F%90%E7%B1%BB%E4%BB%BB%E5%8A%A1%E5%85%B7%E4%BD%93%E6%80%8E%E4%B9%88%E5%AE%8C%E6%88%90%22%5D%0A"})]),fallback:l(()=>[...a[1]||(a[1]=[e(" Loading... ",-1)])]),_:1})),a[5]||(a[5]=t(`<p>两者可以配合使用：AGENTS.md 负责全局边界，Skill 负责具体能力。</p><h2 id="四、一个-skill-的设计示例" tabindex="-1">四、一个 Skill 的设计示例 <a class="header-anchor" href="#四、一个-skill-的设计示例" aria-label="Permalink to &quot;四、一个 Skill 的设计示例&quot;">​</a></h2><p>假设你想让 AI 帮你稳定生成技术文章，可以设计一个“技术博客写作 Skill”。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>触发条件：</span></span>
<span class="line"><span>- 用户要求写技术博客、教程、学习笔记时使用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工作流程：</span></span>
<span class="line"><span>1. 明确读者对象</span></span>
<span class="line"><span>2. 提炼核心概念</span></span>
<span class="line"><span>3. 给出流程图或结构图</span></span>
<span class="line"><span>4. 提供实际案例</span></span>
<span class="line"><span>5. 补充常见坑</span></span>
<span class="line"><span>6. 给出延伸阅读链接</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出格式：</span></span>
<span class="line"><span>- 标题</span></span>
<span class="line"><span>- 概念解释</span></span>
<span class="line"><span>- 图解</span></span>
<span class="line"><span>- 实战步骤</span></span>
<span class="line"><span>- 常见问题</span></span>
<span class="line"><span>- 总结</span></span>
<span class="line"><span></span></span>
<span class="line"><span>约束：</span></span>
<span class="line"><span>- 不编造链接</span></span>
<span class="line"><span>- 不使用无法验证的数据</span></span>
<span class="line"><span>- 不堆砌术语</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><p>这样下次写文章时，就不需要重复说明写作标准。</p><h2 id="五、适合做成-skill-的任务" tabindex="-1">五、适合做成 Skill 的任务 <a class="header-anchor" href="#五、适合做成-skill-的任务" aria-label="Permalink to &quot;五、适合做成 Skill 的任务&quot;">​</a></h2><h3 id="_5-1-高频且格式固定" tabindex="-1">5.1 高频且格式固定 <a class="header-anchor" href="#_5-1-高频且格式固定" aria-label="Permalink to &quot;5.1 高频且格式固定&quot;">​</a></h3><p>例如周报、日报、复盘、会议纪要。</p><h3 id="_5-2-需要多步处理" tabindex="-1">5.2 需要多步处理 <a class="header-anchor" href="#_5-2-需要多步处理" aria-label="Permalink to &quot;5.2 需要多步处理&quot;">​</a></h3><p>例如“读取表格 → 清洗数据 → 统计 → 生成图表 → 写结论”。</p><h3 id="_5-3-需要团队规范" tabindex="-1">5.3 需要团队规范 <a class="header-anchor" href="#_5-3-需要团队规范" aria-label="Permalink to &quot;5.3 需要团队规范&quot;">​</a></h3><p>例如代码评审、组件开发、接口文档生成。</p><h3 id="_5-4-需要复用资产" tabindex="-1">5.4 需要复用资产 <a class="header-anchor" href="#_5-4-需要复用资产" aria-label="Permalink to &quot;5.4 需要复用资产&quot;">​</a></h3><p>例如固定模板、示例文件、校验脚本、品牌素材。</p><h2 id="六、不适合做成-skill-的任务" tabindex="-1">六、不适合做成 Skill 的任务 <a class="header-anchor" href="#六、不适合做成-skill-的任务" aria-label="Permalink to &quot;六、不适合做成 Skill 的任务&quot;">​</a></h2><ul><li>一次性问题</li><li>目标不稳定的探索任务</li><li>高风险决策任务</li><li>需要大量人工判断的任务</li></ul><p>Skill 不是越多越好。如果任务没有稳定流程，硬做成 Skill 反而会限制 Agent。</p><h2 id="七、设计-skill-的五个原则" tabindex="-1">七、设计 Skill 的五个原则 <a class="header-anchor" href="#七、设计-skill-的五个原则" aria-label="Permalink to &quot;七、设计 Skill 的五个原则&quot;">​</a></h2><ol><li><strong>触发条件清晰</strong>：避免 Agent 误用。</li><li><strong>步骤尽量短</strong>：复杂 Skill 拆成多个小 Skill。</li><li><strong>输出格式固定</strong>：方便后续复用和自动化。</li><li><strong>示例优先</strong>：示例比抽象描述更容易被模型执行。</li><li><strong>风险前置</strong>：涉及文件删除、外部发送、生产变更时必须确认。</li></ol><h2 id="八、延伸阅读" tabindex="-1">八、延伸阅读 <a class="header-anchor" href="#八、延伸阅读" aria-label="Permalink to &quot;八、延伸阅读&quot;">​</a></h2><ul><li><a href="https://docs.anthropic.com/en/docs/claude-code/skills" target="_blank" rel="noreferrer">Anthropic：Claude Skills</a></li><li><a href="https://support.anthropic.com/en/articles/12078970-how-to-create-and-use-skills" target="_blank" rel="noreferrer">Anthropic：Create and use skills</a></li><li><a href="https://docs.claude.com/en/docs/agents-and-tools/claude-code/tutorials/how-to-use-the-skill-creator-tool" target="_blank" rel="noreferrer">Anthropic：Skill creator tool</a></li><li><a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol</a></li></ul><p>一句话总结：</p><blockquote><p>Skill 是把个人经验和团队方法沉淀成 AI 可复用能力的方式。</p></blockquote>`,23))])}const q=h(u,[["render",k]]);export{f as __pageData,q as default};
